import React, { useState } from 'react';
import { ExcelRow, CleaningAction } from '../types';
import { Button } from './Button';
import { suggestCleaning } from '../services/geminiService';
import { Trash2, Type, Scissors, Wand2 } from 'lucide-react';

interface CleaningPanelProps {
  data: ExcelRow[];
  columns: string[];
  onUpdateData: (newData: ExcelRow[]) => void;
}

export const CleaningPanel: React.FC<CleaningPanelProps> = ({ data, columns, onUpdateData }) => {
  const [selectedColumn, setSelectedColumn] = useState<string>(columns[0] || '');
  const [suggestions, setSuggestions] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);

  const handleAction = (action: CleaningAction) => {
    let newData = [...data];

    switch (action.type) {
      case 'remove_duplicates':
        const seen = new Set();
        newData = newData.filter(row => {
          const str = JSON.stringify(row);
          return seen.has(str) ? false : seen.add(str);
        });
        break;
      case 'remove_empty':
        newData = newData.filter(row => {
          // Check if all values in the row are empty/null/undefined
          return Object.values(row).some(val => val !== null && val !== '' && val !== undefined);
        });
        break;
      case 'uppercase':
        if (!action.column) return;
        newData = newData.map(row => ({
          ...row,
          [action.column!]: typeof row[action.column!] === 'string' 
            ? (row[action.column!] as string).toUpperCase() 
            : row[action.column!]
        }));
        break;
      case 'lowercase':
        if (!action.column) return;
        newData = newData.map(row => ({
          ...row,
          [action.column!]: typeof row[action.column!] === 'string' 
            ? (row[action.column!] as string).toLowerCase() 
            : row[action.column!]
        }));
        break;
      case 'trim':
        if (!action.column) return;
        newData = newData.map(row => ({
            ...row,
            [action.column!]: typeof row[action.column!] === 'string'
                ? (row[action.column!] as string).trim()
                : row[action.column!]
        }));
        break;
    }

    onUpdateData(newData);
  };

  const getSuggestions = async () => {
    setLoadingSuggestions(true);
    const result = await suggestCleaning(data, columns);
    setSuggestions(result);
    setLoadingSuggestions(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* Manual Tools */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
            <Trash2 className="h-5 w-5 mr-2 text-indigo-600" />
            Row Operations
          </h3>
          <div className="space-y-3">
            <Button 
                variant="secondary" 
                className="w-full justify-start"
                onClick={() => handleAction({ type: 'remove_duplicates' })}
            >
              <Trash2 className="h-4 w-4 mr-2" />
              Remove Exact Duplicates
            </Button>
            <Button 
                variant="secondary" 
                className="w-full justify-start"
                onClick={() => handleAction({ type: 'remove_empty' })}
            >
              <EraserIcon className="h-4 w-4 mr-2" />
              Remove Empty Rows
            </Button>
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                <Type className="h-5 w-5 mr-2 text-indigo-600" />
                Column Operations
            </h3>

            <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">Select Target Column</label>
                <select 
                    value={selectedColumn} 
                    onChange={(e) => setSelectedColumn(e.target.value)}
                    className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 border p-2"
                >
                    {columns.map(col => <option key={col} value={col}>{col}</option>)}
                </select>
            </div>

            <div className="space-y-3">
                <Button 
                    variant="secondary" 
                    className="w-full justify-start"
                    onClick={() => handleAction({ type: 'uppercase', column: selectedColumn })}
                >
                    <span className="font-mono bg-gray-100 px-1 rounded mr-2">AA</span>
                    To Uppercase
                </Button>
                <Button 
                    variant="secondary" 
                    className="w-full justify-start"
                    onClick={() => handleAction({ type: 'lowercase', column: selectedColumn })}
                >
                    <span className="font-mono bg-gray-100 px-1 rounded mr-2">aa</span>
                    To Lowercase
                </Button>
                 <Button 
                    variant="secondary" 
                    className="w-full justify-start"
                    onClick={() => handleAction({ type: 'trim', column: selectedColumn })}
                >
                    <Scissors className="h-4 w-4 mr-2" />
                    Trim Whitespace
                </Button>
            </div>
        </div>
      </div>

      {/* AI Suggestions */}
      <div className="bg-indigo-50 rounded-xl p-6 border border-indigo-100">
        <div className="flex justify-between items-start mb-4">
            <div>
                <h3 className="text-lg font-bold text-indigo-900 flex items-center">
                    <Wand2 className="h-5 w-5 mr-2" />
                    AI Cleaning Suggestions
                </h3>
                <p className="text-indigo-700 text-sm mt-1">Not sure what to clean? Let AI analyze your sample data.</p>
            </div>
            <Button onClick={getSuggestions} isLoading={loadingSuggestions} variant="primary" size="sm">
                Get Suggestions
            </Button>
        </div>

        {suggestions && (
            <div className="bg-white rounded-lg p-4 text-gray-700 text-sm border border-indigo-100">
                <div className="prose prose-sm max-w-none">
                    <p className="whitespace-pre-wrap">{suggestions}</p>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

