import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { FileUpload } from './components/FileUpload';
import { DataView } from './components/DataView';
import { AnalysisPanel } from './components/AnalysisPanel';
import { CleaningPanel } from './components/CleaningPanel';
import { FormulaPanel } from './components/FormulaPanel';
import { ChartPanel } from './components/ChartPanel';
import { AppTab, ExcelRow } from './types';
import { readExcelFile, downloadExcelFile } from './utils/excelUtils';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.UPLOAD);
  const [data, setData] = useState<ExcelRow[]>([]);
  const [columns, setColumns] = useState<string[]>([]);
  const [fileName, setFileName] = useState<string>('');
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileSelect = async (file: File) => {
    setIsProcessing(true);
    try {
      const { data, columns } = await readExcelFile(file);
      setData(data);
      setColumns(columns);
      setFileName(file.name);
      setActiveTab(AppTab.VIEW);
    } catch (error) {
      console.error("Error processing file", error);
      alert("Error reading Excel file. Please ensure it is a valid .xlsx file.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDataUpdate = (newData: ExcelRow[]) => {
    setData(newData);
    // Refresh columns in case keys changed (though unlikely for row operations)
    if (newData.length > 0) {
      setColumns(Object.keys(newData[0]));
    }
  };

  const handleDownload = () => {
    if (data.length === 0) return;
    const newName = fileName.replace('.xlsx', '_modified.xlsx');
    downloadExcelFile(data, newName);
  };

  const renderContent = () => {
    if (activeTab === AppTab.UPLOAD) {
      return <FileUpload onFileSelect={handleFileSelect} isLoading={isProcessing} />;
    }

    if (data.length === 0 && activeTab !== AppTab.UPLOAD) {
       // Fallback if user navigates via code but no data
       return <FileUpload onFileSelect={handleFileSelect} isLoading={isProcessing} />;
    }

    switch (activeTab) {
      case AppTab.VIEW:
        return <DataView data={data} columns={columns} onDownload={handleDownload} />;
      case AppTab.ANALYSIS:
        return <AnalysisPanel data={data} columns={columns} />;
      case AppTab.CLEANING:
        return <CleaningPanel data={data} columns={columns} onUpdateData={handleDataUpdate} />;
      case AppTab.FORMULA:
        return <FormulaPanel columns={columns} />;
      case AppTab.VISUALIZE:
        return <ChartPanel data={data} columns={columns} />;
      default:
        return null;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} fileName={fileName}>
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900">
            {activeTab === AppTab.UPLOAD ? 'Welcome to ExcelAI' : 
             activeTab === AppTab.VIEW ? 'Data Overview' :
             activeTab === AppTab.ANALYSIS ? 'AI Analysis' :
             activeTab === AppTab.CLEANING ? 'Data Cleaning' :
             activeTab === AppTab.FORMULA ? 'Formula Generator' :
             'Visualization'}
        </h1>
        <p className="text-gray-500 mt-1">
            {activeTab === AppTab.UPLOAD ? 'Upload your spreadsheet to get started.' :
             activeTab === AppTab.VIEW ? 'View and export your data.' :
             activeTab === AppTab.ANALYSIS ? 'Gain insights from your data using Gemini AI.' :
             activeTab === AppTab.CLEANING ? 'Clean and standardize your dataset.' :
             activeTab === AppTab.FORMULA ? 'Generate complex formulas instantly.' :
             'Create charts to visualize trends.'}
        </p>
      </div>
      {renderContent()}
    </Layout>
  );
};

export default App;

