                <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700">
                    <ChevronDown className="h-4 w-4" />
                </div>
            </div>
        </div>

        <div className="flex items-center space-x-2">
            <span className="text-sm text-gray-500 mr-2">
                Showing top 100 of {activeFile.data.length} rows
            </span>
            <ExportMenu onExport={(format) => onDownload(activeFile.id, format)} />
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                {activeFile.columns.map((col, idx) => (
                  <th
                    key={idx}
                    scope="col"
                    className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider whitespace-nowrap"
                  >
                    {col}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {displayData.map((row, rowIdx) => (
                <tr key={rowIdx} className="hover:bg-gray-50">
                  {activeFile.columns.map((col, colIdx) => (
                    <td
                      key={`${rowIdx}-${colIdx}`}
                      className="px-6 py-4 whitespace-nowrap text-sm text-gray-900"
                    >
                      {row[col]?.toString() || ''}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { UploadedFile, ExportFormat } from '../types';
import { Button } from './Button';
import { GitCompare, ArrowRightLeft, AlertCircle } from 'lucide-react';
import { downloadExcelFile } from '../utils/excelUtils';
import { ExportMenu } from './ExportMenu';

interface ComparePanelProps {
  files: UploadedFile[];
}

export const ComparePanel: React.FC<ComparePanelProps> = ({ files }) => {
  const [file1Id, setFile1Id] = useState<string>(files[0]?.id || '');
  const [file2Id, setFile2Id] = useState<string>(files[1]?.id || '');
  const [col1, setCol1] = useState<string>('');
  const [col2, setCol2] = useState<string>('');
  const [result, setResult] = useState<{ in1Only: any[], in2Only: any[], common: any[] } | null>(null);

  const file1 = files.find(f => f.id === file1Id);
  const file2 = files.find(f => f.id === file2Id);

  // Initialize columns when files change
  React.useEffect(() => {
    if (file1 && !col1) setCol1(file1.columns[0] || '');
    if (file2 && !col2) setCol2(file2.columns[0] || '');
  }, [file1, file2, col1, col2]);

  if (files.length < 2) {
    return (
      <div className="text-center py-20 bg-white rounded-2xl shadow-sm border border-gray-200">
        <AlertCircle className="h-12 w-12 text-yellow-500 mx-auto mb-4" />
        <h3 className="text-lg font-bold text-gray-900">Not Enough Files</h3>
        <p className="text-gray-500">Please upload at least 2 files to use the comparison feature.</p>
      </div>
    );
  }

  const handleCompare = () => {
    if (!file1 || !file2 || !col1 || !col2) return;

    const set1 = new Set(file1.data.map(r => String(r[col1])));
    const set2 = new Set(file2.data.map(r => String(r[col2])));

    const in1Only = file1.data.filter(r => !set2.has(String(r[col1])));
    const in2Only = file2.data.filter(r => !set1.has(String(r[col2])));

    // For common, we just take rows from file1 that are also in file2
    const common = file1.data.filter(r => set2.has(String(r[col1])));

    setResult({ in1Only, in2Only, common });
  };

  const downloadResult = (data: any[], type: string, format: ExportFormat) => {
    if (data.length === 0) return;
    downloadExcelFile(data, `comparison_${type}.${format}`, format);
  };

  return (
    <div className="space-y-8 max-w-5xl mx-auto">
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-8">
        <div className="flex items-center mb-6 text-gray-900">
            <GitCompare className="h-6 w-6 text-indigo-600 mr-2" />
            <h2 className="text-2xl font-bold">Compare Files</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative">
           {/* Connector Icon */}
           <div className="hidden md:flex absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 bg-gray-100 p-2 rounded-full border border-gray-200 z-10">
                <ArrowRightLeft className="h-5 w-5 text-gray-500" />
           </div>

           {/* Source 1 */}
           <div className="bg-gray-50 p-6 rounded-xl border border-gray-200">
                <h3 className="font-semibold text-gray-700 mb-4">Source File A</h3>
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm text-gray-500 mb-1">Select File</label>
                        <select 
                            value={file1Id} 
                            onChange={(e) => setFile1Id(e.target.value)}
                            className="w-full p-2 border border-gray-300 rounded-lg bg-white"
                        >
                            {files.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-sm text-gray-500 mb-1">Compare Column</label>
                         <select 
                            value={col1} 
                            onChange={(e) => setCol1(e.target.value)}
                            className="w-full p-2 border border-gray-300 rounded-lg bg-white"
                        >
                            {file1?.columns.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                    </div>
                </div>
           </div>

           {/* Source 2 */}
           <div className="bg-gray-50 p-6 rounded-xl border border-gray-200">
                <h3 className="font-semibold text-gray-700 mb-4">Source File B</h3>
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm text-gray-500 mb-1">Select File</label>
                        <select 
                            value={file2Id} 
                            onChange={(e) => setFile2Id(e.target.value)}
                            className="w-full p-2 border border-gray-300 rounded-lg bg-white"
                        >
                            {files.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
                        </select>
                    </div>
                    <div>
                         <label className="block text-sm text-gray-500 mb-1">Compare Column</label>
                         <select 
                            value={col2} 
                            onChange={(e) => setCol2(e.target.value)}
                            className="w-full p-2 border border-gray-300 rounded-lg bg-white"
                        >
                            {file2?.columns.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                    </div>
                </div>
           </div>
        </div>

        <div className="mt-8 flex justify-center">
            <Button size="lg" onClick={handleCompare} disabled={!file1 || !file2}>
                Compare Data
            </Button>
        </div>
      </div>

      {/* Results */}
      {result && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h4 className="font-bold text-lg text-red-600 mb-2">Unique to {file1?.name}</h4>
                <div className="text-3xl font-bold text-gray-900 mb-4">{result.in1Only.length} <span className="text-sm font-normal text-gray-500">rows</span></div>
                <ExportMenu 
                    label="Download" 
                    size="sm" 
                    onExport={(format) => downloadResult(result.in1Only, 'unique_to_A', format)} 
                />
            </div>
             <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h4 className="font-bold text-lg text-green-600 mb-2">Common Rows</h4>
                <div className="text-3xl font-bold text-gray-900 mb-4">{result.common.length} <span className="text-sm font-normal text-gray-500">rows</span></div>
                <ExportMenu 
                    label="Download" 
                    size="sm" 
                    onExport={(format) => downloadResult(result.common, 'common', format)} 
                />
            </div>
             <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
                <h4 className="font-bold text-lg text-blue-600 mb-2">Unique to {file2?.name}</h4>
                <div className="text-3xl font-bold text-gray-900 mb-4">{result.in2Only.length} <span className="text-sm font-normal text-gray-500">rows</span></div>
                 <ExportMenu 
                    label="Download" 
                    size="sm" 
                    onExport={(format) => downloadResult(result.in2Only, 'unique_to_B', format)} 
                />
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { UploadedFile, ExcelRow, CleaningAction, ExportFormat } from '../types';
import { Button } from './Button';
import { suggestCleaning } from '../services/geminiService';
import { Trash2, Type, Scissors, Wand2, PlusSquare, MinusSquare, Download, ChevronDown } from 'lucide-react';
import { downloadExcelFile } from '../utils/excelUtils';
import { ExportMenu } from './ExportMenu';

interface CleaningPanelProps {
  files: UploadedFile[];
  onUpdateFile: (fileId: string, newData: ExcelRow[]) => void;
}

export const CleaningPanel: React.FC<CleaningPanelProps> = ({ files, onUpdateFile }) => {
  const [selectedFileId, setSelectedFileId] = useState<string>(files[0]?.id || '');
  const [selectedColumn, setSelectedColumn] = useState<string>('');
  const [prefixValue, setPrefixValue] = useState('');
  const [suggestions, setSuggestions] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);

  useEffect(() => {
    if (!files.find(f => f.id === selectedFileId) && files.length > 0) {
        setSelectedFileId(files[0].id);
    }
  }, [files, selectedFileId]);

  const activeFile = files.find(f => f.id === selectedFileId);

  useEffect(() => {
    if (activeFile && !activeFile.columns.includes(selectedColumn)) {
        setSelectedColumn(activeFile.columns[0] || '');
    }
  }, [activeFile, selectedColumn]);

  if (!activeFile) return <div className="text-center py-10">No files available.</div>;

  const handleAction = (action: CleaningAction) => {
    let newData = [...activeFile.data];

    switch (action.type) {
      case 'remove_duplicates':
        const seen = new Set();
        newData = newData.filter(row => {
          const str = JSON.stringify(row);
          return seen.has(str) ? false : seen.add(str);
        });
        break;
      case 'remove_empty':
        newData = newData.filter(row => {
          return Object.values(row).some(val => val !== null && val !== '' && val !== undefined);
        });
        break;
      case 'uppercase':
        if (!action.column) return;
        newData = newData.map(row => ({
          ...row,
          [action.column!]: typeof row[action.column!] === 'string' 
            ? (row[action.column!] as string).toUpperCase() 
            : row[action.column!]
        }));
        break;
      case 'lowercase':
        if (!action.column) return;
        newData = newData.map(row => ({
          ...row,
          [action.column!]: typeof row[action.column!] === 'string' 
            ? (row[action.column!] as string).toLowerCase() 
            : row[action.column!]
        }));
        break;
      case 'trim':
        if (!action.column) return;
        newData = newData.map(row => ({
            ...row,
            [action.column!]: typeof row[action.column!] === 'string'
                ? (row[action.column!] as string).trim()
                : row[action.column!]
        }));
        break;
      case 'add_prefix':
        if (!action.column || !action.value) return;
        newData = newData.map(row => ({
            ...row,
            [action.column!]: `${action.value}${row[action.column!] || ''}`
        }));
        break;
      case 'remove_prefix':
        if (!action.column || !action.value) return;
        newData = newData.map(row => {
             const val = String(row[action.column!] || '');
             if (val.startsWith(action.value!)) {
                 return { ...row, [action.column!]: val.substring(action.value!.length) };
             }
             return row;
        });
        break;
    }

    onUpdateFile(activeFile.id, newData);
  };

  const handleExtractColumn = (format: ExportFormat) => {
    if (!selectedColumn) return;
    const extractedData = activeFile.data.map(row => ({
        [selectedColumn]: row[selectedColumn]
    }));
    downloadExcelFile(extractedData, `${activeFile.name}_${selectedColumn}.${format}`, format);
  };

  const getSuggestions = async () => {
    setLoadingSuggestions(true);
    const result = await suggestCleaning(activeFile.data, activeFile.columns);
    setSuggestions(result);
    setLoadingSuggestions(false);
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6">

      {/* File Selector */}
      <div className="mb-6 flex justify-between items-center bg-white p-4 rounded-xl border border-gray-200">
         <span className="font-semibold text-gray-700">Select File to Operate On:</span>
         <div className="relative w-64">
            <select
                value={selectedFileId}
                onChange={(e) => setSelectedFileId(e.target.value)}
                className="appearance-none w-full pl-4 pr-10 py-2 border border-gray-300 rounded-lg bg-white text-gray-700 font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500"
            >
                {files.map(f => (
                    <option key={f.id} value={f.id}>{f.name}</option>
                ))}
            </select>
            <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700">
                <ChevronDown className="h-4 w-4" />
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

        {/* Row Operations */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 h-fit">
          <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
            <Trash2 className="h-5 w-5 mr-2 text-indigo-600" />
            Global Operations
          </h3>
          <div className="space-y-3">
            <Button 
                variant="secondary" 
                className="w-full justify-start"
                onClick={() => handleAction({ type: 'remove_duplicates' })}
            >
              <Trash2 className="h-4 w-4 mr-2" />
              Remove Exact Duplicates
            </Button>
            <Button 
                variant="secondary" 
                className="w-full justify-start"
                onClick={() => handleAction({ type: 'remove_empty' })}
            >
              <EraserIcon className="h-4 w-4 mr-2" />
              Remove Empty Rows
            </Button>
          </div>
        </div>

        {/* Column Operations */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <h3 className="text-lg font-bold text-gray-900 mb-4 flex items-center">
                <Type className="h-5 w-5 mr-2 text-indigo-600" />
                Column Operations
            </h3>

            <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">Select Target Column</label>
                <select 
                    value={selectedColumn} 
                    onChange={(e) => setSelectedColumn(e.target.value)}
                    className="block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 border p-2"
                >
                    {activeFile.columns.map(col => <option key={col} value={col}>{col}</option>)}
                </select>
            </div>

            <div className="space-y-4">
                <div className="grid grid-cols-2 gap-2">
                    <Button 
                        variant="secondary" 
                        className="w-full justify-start text-xs"
                        onClick={() => handleAction({ type: 'uppercase', column: selectedColumn })}
                    >
                        <span className="font-mono bg-gray-100 px-1 rounded mr-2">AA</span>
                        Uppercase
                    </Button>
                    <Button 
                        variant="secondary" 
                        className="w-full justify-start text-xs"
                        onClick={() => handleAction({ type: 'lowercase', column: selectedColumn })}
                    >
                        <span className="font-mono bg-gray-100 px-1 rounded mr-2">aa</span>
                        Lowercase
                    </Button>
                     <Button 
                        variant="secondary" 
                        className="w-full justify-start text-xs"
                        onClick={() => handleAction({ type: 'trim', column: selectedColumn })}
                    >
                        <Scissors className="h-3 w-3 mr-2" />
                        Trim Space
                    </Button>

                    <div className="relative">
                      <ExportMenu 
                         onExport={handleExtractColumn} 
                         label="Extract"
                         size="sm"
                         className="w-full"
                         variant="secondary"
                      />
                    </div>
                </div>

                <div className="pt-4 border-t border-gray-100">
                    <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase">Text Manipulation</label>
                    <div className="flex space-x-2 mb-2">
                         <input 
                            type="text" 
                            placeholder="Prefix value"
                            value={prefixValue}
                            onChange={(e) => setPrefixValue(e.target.value)}
                            className="flex-1 rounded-md border-gray-300 border p-1 text-sm"
                        />
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                         <Button 
                            variant="secondary" 
                            size="sm"
                            disabled={!prefixValue}
                            onClick={() => handleAction({ type: 'add_prefix', column: selectedColumn, value: prefixValue })}
                        >
                            <PlusSquare className="h-4 w-4 mr-1" /> Add Prefix
                        </Button>
                        <Button 
                            variant="secondary" 
                            size="sm"
                            disabled={!prefixValue}
                            onClick={() => handleAction({ type: 'remove_prefix', column: selectedColumn, value: prefixValue })}
                        >
                            <MinusSquare className="h-4 w-4 mr-1" /> Del Prefix
                        </Button>
                    </div>
                </div>
            </div>
        </div>
      </div>

      {/* AI Suggestions */}
      <div className="bg-indigo-50 rounded-xl p-6 border border-indigo-100">
        <div className="flex justify-between items-start mb-4">
            <div>
                <h3 className="text-lg font-bold text-indigo-900 flex items-center">
                    <Wand2 className="h-5 w-5 mr-2" />
                    AI Cleaning Suggestions
                </h3>
                <p className="text-indigo-700 text-sm mt-1">Not sure what to clean? Let AI analyze your sample data.</p>
            </div>
            <Button onClick={getSuggestions} isLoading={loadingSuggestions} variant="primary" size="sm">
                Get Suggestions
            </Button>
        </div>

        {suggestions && (
            <div className="bg-white rounded-lg p-4 text-gray-700 text-sm border border-indigo-100">
                <div className="prose prose-sm max-w-none">
                    <p className="whitespace-pre-wrap">{suggestions}</p>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

const EraserIcon = ({ className }: { className?: string }) => (
    <svg className={className} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m7 21-4.3-4.3c-1-1-1-2.5 0-3.4l9.6-9.6c1-1 2.5-1 3.4 0l5.6 5.6c1 1 1 2.5 0 3.4L13 21"/><path d="M22 21H7"/><path d="m5 11 9 9"/></svg>
);

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { FileUpload } from './components/FileUpload';
import { DataView } from './components/DataView';
import { AnalysisPanel } from './components/AnalysisPanel';
import { CleaningPanel } from './components/CleaningPanel';
import { FormulaPanel } from './components/FormulaPanel';
import { ChartPanel } from './components/ChartPanel';
import { ComparePanel } from './components/ComparePanel';
import { AppTab, UploadedFile, ExcelRow, ExportFormat } from './types';
import { readExcelFile, downloadExcelFile } from './utils/excelUtils';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.UPLOAD);
  const [files, setFiles] = useState<UploadedFile[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileSelect = async (file: File) => {
    setIsProcessing(true);
    try {
      const { data, columns } = await readExcelFile(file);
      const newFile: UploadedFile = {
        id: crypto.randomUUID(),
        name: file.name,
        data,
        columns
      };
      setFiles(prev => [...prev, newFile]);

    } catch (error) {
      console.error("Error processing file", error);
      alert("Error reading file. Please ensure it is a valid .xlsx, .xls, .csv, or .txt file.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const handleFileUpdate = (fileId: string, newData: ExcelRow[]) => {
    setFiles(prev => prev.map(f => {
        if (f.id === fileId) {
            return {
                ...f,
                data: newData,
                columns: newData.length > 0 ? Object.keys(newData[0]) : []
            };
        }
        return f;
    }));
  };

  const handleDownload = (fileId: string, format: ExportFormat) => {
    const file = files.find(f => f.id === fileId);
    if (!file) return;

    // Create new name preserving original name but changing extension and adding modifier
    const originalName = file.name.substring(0, file.name.lastIndexOf('.')) || file.name;
    const newName = `${originalName}_modified.${format}`;

    downloadExcelFile(file.data, newName, format);
  };

  const renderContent = () => {
    if (activeTab === AppTab.UPLOAD) {
      return (
        <FileUpload 
            files={files} 
            onFileSelect={handleFileSelect} 
            onRemoveFile={handleRemoveFile} 
            isLoading={isProcessing} 
        />
      );
    }

    if (files.length === 0) {
       return (
         <div className="text-center py-20">
           <p className="text-gray-500 mb-4">No files uploaded yet.</p>
           <button 
             onClick={() => setActiveTab(AppTab.UPLOAD)}
             className="text-indigo-600 hover:text-indigo-800 font-medium"
           >
             Go to File Manager
           </button>
         </div>
       );
    }

    switch (activeTab) {
      case AppTab.VIEW:
        return <DataView files={files} onDownload={handleDownload} />;
      case AppTab.COMPARE:
        return <ComparePanel files={files} />;
      case AppTab.ANALYSIS:
        return <AnalysisPanel files={files} />;
      case AppTab.CLEANING:
        return <CleaningPanel files={files} onUpdateFile={handleFileUpdate} />;
      case AppTab.FORMULA:
        return <FormulaPanel files={files} />;
      case AppTab.VISUALIZE:
        return <ChartPanel files={files} />;
      default:
        return null;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} fileCount={files.length}>
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900">
            {activeTab === AppTab.UPLOAD ? 'File Manager' : 
             activeTab === AppTab.VIEW ? 'Data Overview' :
             activeTab === AppTab.COMPARE ? 'Compare Files' :
             activeTab === AppTab.ANALYSIS ? 'AI Analysis' :
             activeTab === AppTab.CLEANING ? 'Operations & Cleaning' :
             activeTab === AppTab.FORMULA ? 'Formula Generator' :
             'Visualization'}
        </h1>
        <p className="text-gray-500 mt-1">
            {activeTab === AppTab.UPLOAD ? 'Manage your uploaded spreadsheets and data files.' :
             activeTab === AppTab.VIEW ? 'View and export your data.' :
             activeTab === AppTab.COMPARE ? 'Identify differences between two datasets.' :
             activeTab === AppTab.ANALYSIS ? 'Gain insights from your data using Gemini AI.' :
             activeTab === AppTab.CLEANING ? 'Clean, modify, and extract data.' :
             activeTab === AppTab.FORMULA ? 'Generate complex formulas instantly.' :
             'Create charts to visualize trends.'}
        </p>
      </div>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Download, ChevronDown, FileSpreadsheet, FileText, FileType } from 'lucide-react';
import { Button } from './Button';
