interface MergePanelProps {
  files: UploadedFile[];
}

interface ProcessedMerge {
    id: string;
    name: string;
    data: ExcelRow[];
    columns: string[];
    fileCount: number;
    timestamp: Date;
}

export const MergePanel: React.FC<MergePanelProps> = ({ files }) => {
  const [selectedFileIds, setSelectedFileIds] = useState<Set<string>>(new Set());
  const [mergedResults, setMergedResults] = useState<ProcessedMerge[]>([]);
  const [isMerging, setIsMerging] = useState(false);

  const toggleFile = (id: string) => {
    const next = new Set(selectedFileIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedFileIds(next);
  };

  const handleMerge = () => {
    if (selectedFileIds.size < 2) return;
    setIsMerging(true);

    const selectedFiles = files.filter(f => selectedFileIds.has(f.id));

    // Combine all data
    let combinedData: ExcelRow[] = [];
    const allUniqueColumns = new Set<string>();

    selectedFiles.forEach(file => {
        combinedData = [...combinedData, ...file.data];
        file.columns.forEach(col => allUniqueColumns.add(col));
    });

    const result: ProcessedMerge = {
        id: crypto.randomUUID(),
        name: `Merged_${selectedFiles.length}_Files_${new Date().getTime()}`,
        data: combinedData,
        columns: Array.from(allUniqueColumns),
        fileCount: selectedFiles.length,
        timestamp: new Date()
    };

    setMergedResults(prev => [result, ...prev]);
    setIsMerging(false);
    setSelectedFileIds(new Set()); // Reset selection after merge
  };

  if (files.length < 2) {
    return (
      <div className="text-center py-20 bg-white rounded-2xl shadow-sm border border-gray-200 max-w-2xl mx-auto">
        <Combine className="h-12 w-12 text-indigo-400 mx-auto mb-4" />
        <h3 className="text-lg font-bold text-gray-900">Merge Workspace</h3>
        <p className="text-gray-500 mt-2 px-6">
          You need at least two files in the File Manager to use the merge feature.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Selection Area */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
            <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-gray-900 flex items-center">
                    <Layers className="h-5 w-5 mr-2 text-indigo-600" />
                    Select Files to Merge
                </h3>
                <span className="text-xs font-semibold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
                    {selectedFileIds.size} Selected
                </span>
            </div>

            <div className="space-y-2 max-h-[400px] overflow-y-auto mb-6 pr-2 custom-scrollbar">
                {files.map(file => {
                    const isSelected = selectedFileIds.has(file.id);
                    return (
                        <div 
                            key={file.id}
                            onClick={() => toggleFile(file.id)}
                            className={`flex items-center p-4 rounded-lg border cursor-pointer transition-all ${
                                isSelected 
                                ? 'bg-indigo-50 border-indigo-200 ring-1 ring-indigo-200' 
                                : 'bg-white border-gray-100 hover:border-gray-300'
                            }`}
                        >
                            <div className="mr-4">
                                {isSelected ? (
                                    <CheckSquare className="h-5 w-5 text-indigo-600" />
                                ) : (
                                    <Square className="h-5 w-5 text-gray-300" />
                                )}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className={`text-sm font-medium truncate ${isSelected ? 'text-indigo-900' : 'text-gray-900'}`}>
                                    {file.name}
                                </p>
                                <p className="text-xs text-gray-500">
                                    {file.data.length} rows • {file.columns.length} columns
                                </p>
                            </div>
                        </div>
                    );
                })}
            </div>

            <Button 
                onClick={handleMerge} 
                disabled={selectedFileIds.size < 2 || isMerging}
                className="w-full py-4 rounded-xl shadow-md shadow-indigo-100"
                isLoading={isMerging}
            >
                <Combine className="h-5 w-5 mr-2" />
                Process Merge
            </Button>
            <p className="text-center text-xs text-gray-400 mt-4">
                Merged files will include the union of all columns from selected sources.
            </p>
        </div>

        {/* Results Staging Area */}
        <div className="space-y-4">
            <h3 className="text-lg font-bold text-gray-900 flex items-center px-2">
                <ArrowDown className="h-5 w-5 mr-2 text-green-600" />
                Merge History
            </h3>

            {mergedResults.length === 0 ? (
                <div className="h-[400px] bg-gray-50 rounded-xl border border-dashed border-gray-300 flex flex-col items-center justify-center text-gray-400 p-8 text-center">
                    <p className="text-sm">Processed merged files will appear here for download.</p>
                </div>
            ) : (
                <div className="space-y-3">
                    {mergedResults.map(result => (
                        <div key={result.id} className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm hover:border-indigo-300 transition-colors animate-fade-in">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center space-x-3">
                                    <div className="bg-green-100 p-3 rounded-lg text-green-700">
                                        <FileSpreadsheet className="h-6 w-6" />
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-gray-900 text-sm truncate max-w-[200px] md:max-w-[300px]">
                                            {result.name}
                                        </h4>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="text-[10px] bg-gray-100 text-gray-600 px-1.5 py-0.5 rounded font-bold uppercase tracking-tighter">
                                                {result.fileCount} Sources
                                            </span>
                                            <span className="text-xs text-gray-500">
                                                {result.data.length} rows • {result.columns.length} columns
                                            </span>
                                        </div>
                                    </div>
                                </div>
                                <ExportMenu 
                                    trigger={
                                        <button className="p-2.5 hover:bg-gray-100 rounded-full transition-colors text-gray-500">
                                            <MoreVertical className="h-5 w-5" />
                                        </button>
                                    }
                                    onExport={(format) => downloadExcelFile(result.data, result.name, format)}
                                />
                            </div>
                            <div className="mt-4 pt-3 border-t border-gray-50 flex justify-between items-center">
                                <span className="text-[10px] text-gray-400">Created {result.timestamp.toLocaleTimeString()}</span>
                                <span className="text-[10px] text-indigo-400 font-medium">Ready for export</span>
                            </div>
                        </div>
                    ))}
                    <Button 
                        variant="ghost" 
                        size="sm" 
                        onClick={() => setMergedResults([])}
                        className="w-full text-gray-400"
                    >
                        Clear History
                    </Button>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { FileUpload } from './components/FileUpload';
import { DataView } from './components/DataView';
import { AnalysisPanel } from './components/AnalysisPanel';
import { CleaningPanel } from './components/CleaningPanel';
import { FormulaPanel } from './components/FormulaPanel';
import { ChartPanel } from './components/ChartPanel';
import { ComparePanel } from './components/ComparePanel';
import { MergePanel } from './components/MergePanel';
import { AppTab, UploadedFile, ExcelRow, ExportFormat, CleaningAction } from './types';
import { readExcelFile, downloadExcelFile } from './utils/excelUtils';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.UPLOAD);
  const [files, setFiles] = useState<UploadedFile[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  // Bridge State: Passing actions from Formula AI to Operations
  const [pendingCleaningAction, setPendingCleaningAction] = useState<{
    fileId: string;
    action: CleaningAction;
  } | null>(null);

  const handleFileSelect = async (file: File) => {
    setIsProcessing(true);
    try {
      const { data, columns } = await readExcelFile(file);
      const newFile: UploadedFile = {
        id: crypto.randomUUID(),
        name: file.name,
        data,
        columns
      };
      setFiles(prev => [...prev, newFile]);

    } catch (error) {
      console.error("Error processing file", error);
      alert("Error reading file. Please ensure it is a valid .xlsx, .xls, .csv, or .txt file.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleRemoveFile = (id: string) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  const handleFileUpdate = (fileId: string, newData: ExcelRow[]) => {
    setFiles(prev => prev.map(f => {
        if (f.id === fileId) {
            return {
                ...f,
                data: newData,
                columns: newData.length > 0 ? Object.keys(newData[0]) : []
            };
        }
        return f;
    }));
  };

  const handleDownload = (fileId: string, format: ExportFormat) => {
    const file = files.find(f => f.id === fileId);
    if (!file) return;

    // Create new name preserving original name but changing extension and adding modifier
    const originalName = file.name.substring(0, file.name.lastIndexOf('.')) || file.name;
    const newName = `${originalName}_modified.${format}`;

    downloadExcelFile(file.data, newName, format);
  };

  // Bridge Function
  const handleAddToPipeline = (fileId: string, formula: string, targetColumn: string) => {
    setPendingCleaningAction({
      fileId,
      action: {
        type: 'apply_formula',
        column: targetColumn,
        value: formula
      }
    });
    setActiveTab(AppTab.CLEANING);
  };

  const clearPendingAction = () => {
    setPendingCleaningAction(null);
  };

  const renderContent = () => {
    if (activeTab === AppTab.UPLOAD) {
      return (
        <FileUpload 
            files={files} 
            onFileSelect={handleFileSelect} 
            onRemoveFile={handleRemoveFile} 
            isLoading={isProcessing} 
        />
      );
    }

    if (files.length === 0) {
       return (
         <div className="text-center py-20">
           <p className="text-gray-500 mb-4">No files uploaded yet.</p>
           <button 
             onClick={() => setActiveTab(AppTab.UPLOAD)}
             className="text-indigo-600 hover:text-indigo-800 font-medium"
           >
             Go to File Manager
           </button>
         </div>
       );
    }

    return (
      <>
        {/* Persistent Cleaning Panel: kept mounted but hidden when inactive to preserve state */}
        <div className={activeTab === AppTab.CLEANING ? 'block' : 'hidden'}>
          <CleaningPanel 
            files={files} 
            onUpdateFile={handleFileUpdate} 
            incomingAction={pendingCleaningAction}
            onActionHandled={clearPendingAction}
          />
        </div>

        {/* Other workspace tabs */}
        {activeTab === AppTab.VIEW && <DataView files={files} onDownload={handleDownload} />}
        {activeTab === AppTab.COMPARE && <ComparePanel files={files} />}
        {activeTab === AppTab.MERGE && <MergePanel files={files} />}
        {activeTab === AppTab.ANALYSIS && <AnalysisPanel files={files} />}
        {activeTab === AppTab.FORMULA && <FormulaPanel files={files} onAddToPipeline={handleAddToPipeline} />}
        {activeTab === AppTab.VISUALIZE && <ChartPanel files={files} />}
      </>
    );
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} fileCount={files.length}>
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-gray-900">
            {activeTab === AppTab.UPLOAD ? 'File Manager' : 
             activeTab === AppTab.VIEW ? 'Data Overview' :
             activeTab === AppTab.COMPARE ? 'Compare Files' :
             activeTab === AppTab.MERGE ? 'Merge Files' :
             activeTab === AppTab.ANALYSIS ? 'AI Analysis' :
             activeTab === AppTab.CLEANING ? 'Operations & Cleaning' :
             activeTab === AppTab.FORMULA ? 'Formula Generator' :
             'Visualization'}
        </h1>
        <p className="text-gray-500 mt-1">
            {activeTab === AppTab.UPLOAD ? 'Manage your uploaded spreadsheets and data files.' :
             activeTab === AppTab.VIEW ? 'View and export your data.' :
             activeTab === AppTab.COMPARE ? 'Identify differences between two datasets.' :
             activeTab === AppTab.MERGE ? 'Combine multiple datasets into one.' :
             activeTab === AppTab.ANALYSIS ? 'Gain insights from your data using Gemini AI.' :
             activeTab === AppTab.CLEANING ? 'Clean, modify, and extract data.' :
             activeTab === AppTab.FORMULA ? 'Generate complex formulas instantly.' :
             'Create charts to visualize trends.'}
        </p>
      </div>
      {renderContent()}
    </Layout>
  );
};

export default App;

